using System.Diagnostics;
using TextAnalysis;

const int WarmupIterations = 100;
const int BenchmarkIterations = 10_000;

string sampleText = BuildSampleText();
var analyzer = new TextAnalyzer(sampleText);

// Warmup
for (int i = 0; i < WarmupIterations; i++)
{
    analyzer.AverageWordLength();
    analyzer.WordLengthHistogram();
    analyzer.UniqueWordCount();
}

var results = new Dictionary<string, List<double>>();
results["AverageWordLength"] = Measure(() => analyzer.AverageWordLength());
results["WordLengthHistogram"] = Measure(() => analyzer.WordLengthHistogram());
results["UniqueWordCount"] = Measure(() => analyzer.UniqueWordCount());

string tfm = System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {tfm}");
Console.WriteLine($"{"Method",-25} {"Mean (μs)",>12} {"StdDev (μs)",>12} {"Median (μs)",>12} {"Min (μs)",>12} {"Max (μs)",>12}");
Console.WriteLine(new string('-', 87));

foreach (var (name, timings) in results)
{
    timings.Sort();
    double mean = timings.Average();
    double median = timings[timings.Count / 2];
    double min = timings.Min();
